+    fn output_excerpt(bytes: &[u8], max_chars: usize) -> String {
+        let text = String::from_utf8_lossy(bytes);
+        if text.chars().count() <= max_chars {
+            text.into_owned()
+        } else {
+            let mut truncated = text.chars().take(max_chars).collect::<String>();
+            truncated.push_str("...");
+            truncated
+        }
+    }
